def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 1.0
        factor = 1.0
        penalty = 0.0
        bonus = 1.0
        decay = 1.0
        for j in range(1, 15):
            if j % 2 == 0:
                factor *= (1.02 + 0.005 * j)
            if j % 4 == 1:
                factor *= (0.97 - 0.004 * j)
            if ratio < 0.12 * j:
                score += np.tanh(ratio * j) * (j ** 1.5) * factor
            else:
                score += (np.sqrt(j*j + 1) + np.exp(-ratio*j)) * factor / (j + 3)
            if (cap * j + j*j) % 9 == 0:
                score *= 1.06
                penalty -= 0.02 * j
            elif (cap + item * j) % 11 == 0:
                penalty += 0.03 * j
            if j == 7:
                for k in range(1, 7):
                    diff = cap - item * (k**3)
                    if diff > 5:
                        if diff % (k+3) == 0:
                            penalty += np.cbrt(diff) / (k + 4)
                        else:
                            penalty -= np.log1p(abs(diff)) / (k + 3)
                    else:
                        penalty -= abs(diff)**1.1 / (k + 6)
            if ratio > 0.8 and j % 3 == 0:
                bonus *= 1.15 + 0.015 * j
            elif ratio < 0.25 and j % 5 == 0:
                bonus *= 0.88 - 0.012 * j
            if j % 6 == 2 and cap % (j+2) == 0:
                penalty += np.cos(j * ratio) * 0.6
            decay *= (0.995 + 0.0005 * j)
        score += penalty * 0.9
        score *= bonus
        score *= decay
        if score < 0.5:
            priorities[i] = -score * (np.log1p(cap + item*2) + np.sqrt(cap)*1.2)
        else:
            if cap > item * 3:
                priorities[i] = -score / (np.sqrt(cap) + 1.5) * (1 + ratio*1.1)
            else:
                priorities[i] = -score / (cap + 5) * np.exp(-ratio**2.5)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.96
        elif cap % 4 == 1:
            priorities[i] *= 1.03
        if cap > 50 and ratio < 0.5:
            priorities[i] *= 0.95
        if abs(cap - item*2) < 10:
            priorities[i] *= 1.1
        if np.isclose(np.sqrt(cap) % 1, 0, atol=1e-2):
            priorities[i] *= 0.93
    return priorities
